import { generateText } from 'ai';
import { vex } from '@vex_dev/sdk';

const vexMiddleware = vex({
  orgId: process.env.VEX_ORG_ID!,
  apiKey: process.env.VEX_API_KEY!,
  rules: {
    hallucination: 'block',
    structured: { schema: 'CustomerResponse' },
    tenantIsolation: true
  }
});

export async function generateCustomerResponse(prompt: string, tenantId: string) {
  const result = await vexMiddleware(
    () => generateText({
      model: 'gpt-4o',
      prompt,
      temperature: 0.1,
      maxTokens: 1000
    }),
    { tenantId, sensitivity: 'high' }
  );
  return result.output;
}

import { streamText } from 'ai';
import { vex } from '@vex_dev/sdk';

const streamVex = vex({
  orgId: process.env.VEX_ORG_ID!,
  rules: {
    streaming: {
      hallucination: 'block',
      pii: 'redact',
      rateLimit: { rpm: 30 }
    }
  }
});

export async function streamSupportChat({
  messages,
  tenantId
}: {
  messages: any[];
  tenantId: string;
}) {
  const stream = await streamVex(
    () => streamText({
      model: 'gpt-4o',
      messages,
      tools: {
        validatePolicy: {
          // tool definition
        }
      }
    }),
    { tenantId, context: 'support-chat' }
  );

  return stream;
}

